// 函數原型
BollingerBand(price, length, _band)

// 等同於
= Average(price, length) + _band * StandardDev(price, length, 1)

input: Length(20), UpperBand(2), LowerBand(2);
variable: up(0), down(0), mid(0);
up   = BollingerBand(Close, Length, UpperBand);
down = BollingerBand(Close, Length, -1 * LowerBand);
mid  = (up + down) / 2;
Plot1(up, "上軌"); Plot2(mid, "中軌"); Plot3(down, "下軌");

// 連續 5 日上軌下降、下軌上升 = 帶寬收縮
if trueall(up < up[1], 5)
   and trueall(down > down[1], 5)
then ret = 1;
